#!/usr/bin/env python3
"""Send Telegram message to Discord DM"""
import os
import sys
import requests

DISCORD_TOKEN = os.environ.get("DISCORD_BOT_TOKEN", "")
DISCORD_USER_ID = "817750913405157406"
DISCORD_API = "https://discord.com/api/v10"

def get_dm_channel():
    """Create/get DM channel with user."""
    headers = {
        "Authorization": f"Bot {DISCORD_TOKEN}",
        "Content-Type": "application/json"
    }
    r = requests.post(
        f"{DISCORD_API}/users/@me/channels",
        headers=headers,
        json={"recipient_id": DISCORD_USER_ID},
        timeout=10
    )
    if r.status_code == 200:
        return r.json().get("id")
    print(f"[TG->DC] Failed to create DM channel: {r.status_code} {r.text}", file=sys.stderr)
    return None

def send_to_discord(text):
    if not text or text.strip() == "":
        return True

    channel_id = get_dm_channel()
    if not channel_id:
        return False

    headers = {
        "Authorization": f"Bot {DISCORD_TOKEN}",
        "Content-Type": "application/json"
    }
    payload = {
        "content": text
    }

    r = requests.post(
        f"{DISCORD_API}/channels/{channel_id}/messages",
        headers=headers,
        json=payload,
        timeout=10
    )
    if r.status_code == 200:
        print(f"[TG->DC] Sent: {text[:50]}")
        return True
    else:
        print(f"[TG->DC] Failed: {r.status_code} {r.text}", file=sys.stderr)
        return False

if __name__ == "__main__":
    text = sys.argv[1] if len(sys.argv) > 1 else sys.stdin.read().strip()
    if text:
        ok = send_to_discord(text)
        sys.exit(0 if ok else 1)

